B.adk=new A.bn("Zasady Og\xf3lne:",null,B.bY,null,null,null,null,null,null)
B.ad1=new A.bn("\u2022 Typujemy wyniki mecz\xf3w w regulaminowym czasie gry.\n\u2022 W fazie pucharowej dodatkowo wybieramy dru\u017cyn\u0119, kt\xf3ra awansuje dalej.",null,null,null,null,null,null,null,null)
B.hM=new A.df(null,12,null,null)
B.add=new A.bn("Punktacja - Faza Grupowa:",null,B.bY,null,null,null,null,null,null)
B.ado=new A.bn("\u2022 Dok\u0142adny wynik: 5 pkt\n\u2022 Rozstrzygni\u0119cie i r\xf3\u017cnica bramek: 2 pkt\n\u2022 Tylko rozstrzygni\u0119cie (zwyci\u0119zca/remis): 1 pkt",null,null,null,null,null,null,null,null)
B.adC=new A.bn("Punktacja - Faza Pucharowa:",null,B.bY,null,null,null,null,null,null)
B.ads=new A.bn("\u2022 Wyb\xf3r zwyci\u0119zcy (awans): 2 pkt\n\u2022 Dok\u0142adny wynik (90 min): 4 pkt\n\u2022 Mo\u017cliwe zdobycie \u0142\u0105cznie 6 pkt za mecz.",null,null,null,null,null,null,null,null)
B.ada=new A.bn("Typy D\u0142ugoterminowe:",null,B.bY,null,null,null,null,null,null)
B.ad9=new A.bn("\u2022 Trafienie Mistrza: 15 pkt\n\u2022 Trafienie Kr\xf3la Strzelc\xf3w: 10 pkt\n\u2022 Kr\xf3l strzelc\xf3w: brak mo\u017cliwo\u015bci zmiany po rozpocz\u0119ciu turnieju.\n\u2022 Mistrz: zmiana mo\u017cliwa do startu fazy pucharowej. Pierwsza zmiana kosztuje 5 pkt (odejmowane jednorazowo), kolejne zmiany s\u0105 bezp\u0142atne.",null,null,null,null,null,null,null,null)
B.adc=new A.bn("Zak\u0142ady Specjalne:",null,B.bY,null,null,null,null,null,null)
B.adA=new A.bn("\u2022 Zasady punktowania i rozliczania zak\u0142ad\xf3w specjalnych b\u0119d\u0105 opisane bezpo\u015brednio w zak\u0142adce danego zak\u0142adu specjalnego.",null,null,null,null,null,null,null,null)
B.adx=new A.bn("Zasady Rozstrzygania Remis\xf3w (Ex Aequo):",null,B.bY,null,null,null,null,null,null)
B.adI=new A.bn("W przypadku uzyskania przez kilku uczestnik\xf3w tej samej liczby punkt\xf3w, nagrody przewidziane dla zajmowanych przez nich miejsc s\u0105 sumowane i dzielone po r\xf3wno pomi\u0119dzy tych uczestnik\xf3w.\n\nPrzyk\u0142ad: Je\u015bli 3 osoby zajm\u0105 ex aequo 1. miejsce:\n\u2022 \u0141\u0105czy si\u0119 nagrody za 1., 2. i 3. miejsce (np. 50% + 30% + 20% = 100% puli).\n\u2022 Ca\u0142a kwota jest dzielona po r\xf3wno na te 3 osoby.\n\u2022 W takim przypadku nie przyznaje si\u0119 ju\u017c oddzielnie 2. i 3. miejsca.",null,null,null,null,null,null,null,null)
